from qiskit.circuit.quantumcircuit import QuantumCircuit


def template_nct_9c_12():
    """
    Template 9c_12:

    .. code-block:: text

        q_0: в”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җ
             в”Ңв”Җв”ҙв”Җв”җ  в”Ӯ  в”Ңв”Җв”ҙв”Җв”җв”Ңв”Җв”ҙв”Җв”җ  в”Ӯ  в”Ңв”Җв”ҙв”Җв”җ  в”Ӯ    в”Ӯ  в”Ңв”Җв”ҙв”Җв”җ
        q_1: в”Ө X в”ңв”Җв”Җв– в”Җв”Җв”Ө X в”ңв”Ө X в”ңв”Җв”Җв”јв”Җв”Җв”Ө X в”ңв”Җв”Җв– в”Җв”Җв”Җв”Җв”јв”Җв”Җв”Ө X в”ң
             в””в”Җв”¬в”Җв”ҳв”Ңв”Җв”ҙв”Җв”җв””в”Җв”Җв”Җв”ҳв””в”Җв”¬в”Җв”ҳв”Ңв”Җв”ҙв”Җв”җв””в”Җв”¬в”Җв”ҳв”Ңв”Җв”ҙв”Җв”җв”Ңв”Җв”ҙв”Җв”җв””в”Җв”¬в”Җв”ҳ
        q_2: в”Җв”Җв– в”Җв”Җв”Ө X в”ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв– в”Җв”Җв”Ө X в”ңв”Җв”Җв– в”Җв”Җв”Ө X в”ңв”Ө X в”ңв”Җв”Җв– в”Җв”Җ
                  в””в”Җв”Җв”Җв”ҳ          в””в”Җв”Җв”Җв”ҳ     в””в”Җв”Җв”Җв”ҳв””в”Җв”Җв”Җв”ҳ

    Returns:
        QuantumCircuit: template as a quantum circuit.
    """
    qc = QuantumCircuit(3)
    qc.ccx(0, 2, 1)
    qc.ccx(0, 1, 2)
    qc.cx(0, 1)
    qc.ccx(0, 2, 1)
    qc.cx(0, 2)
    qc.ccx(0, 2, 1)
    qc.ccx(0, 1, 2)
    qc.cx(0, 2)
    qc.ccx(0, 2, 1)
    return qc
